13	type Item = { type: string };
14	
15	type Scenario = {
16	  customer: { yearsWithMHPCO: number };
17	  steps: Array<{ op: "quote"; items: Item[] }>;
18	};
19	
20	type QuoteResult = { premium: number };
21	
22	const COMPONENT_BLOCK_SIZE = 3;
23	const COMPONENT_BLOCK_PREMIUM = 60;
24	
25	const formsComponentBlock = (items: Item[]): boolean =>
26	  items.length === COMPONENT_BLOCK_SIZE && items.every((item) => item.type === items[0].type);
27	
28	const sumOfBasePremiums = (items: Item[]): number =>
29	  items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
30	
31	const groupByType = (items: Item[]): Item[][] => {
32	  const groups = new Map<string, Item[]>();
33	  for (const item of items) {
34	    const existing = groups.get(item.type) ?? [];
35	    existing.push(item);
36	    groups.set(item.type, existing);
37	  }
38	  return Array.from(groups.values());
39	};
40	
41	const basePremiumForGroup = (group: Item[]): number =>
42	  formsComponentBlock(group) ? COMPONENT_BLOCK_PREMIUM : sumOfBasePremiums(group);
43	
44	const basePremiumFor = (items: Item[]): number =>
45	  groupByType(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
46	
47	const quotePremium = (items: Item[]): QuoteResult => {
48	  const base = basePremiumFor(items);
49	  return { premium: Math.ceil(base + base * FIRST_INSURANCE_RATE + PROCESSING_FEE) };
50	};
51	
52	export const processScenario = (scenario: Scenario): { results: QuoteResult[] } => {
53	  const results = scenario.steps.map((step) => quotePremium(step.items));
54	  return { results };
55	};
